import 'package:flutter/material.dart';
import 'dart:convert';
import 'dart:ui_web' as ui;
import 'dart:html' as html;

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Web Native Emoji',
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.deepPurple),
        useMaterial3: true,
      ),
      home: const EmojiReactionPage(),
    );
  }
}

class EmojiReactionPage extends StatefulWidget {
  const EmojiReactionPage({Key? key}) : super(key: key);

  @override
  State<EmojiReactionPage> createState() => _EmojiReactionPageState();
}

class _EmojiReactionPageState extends State<EmojiReactionPage> {
  final String _viewType = 'native-emoji-view-${DateTime.now().millisecondsSinceEpoch}';
  final Map<String, int> _reactionCounts = {};
  bool _webViewLoaded = false;
  late html.MessageChannel _channel;
  late html.IFrameElement _iframeElement;

  // The HTML content for our emoji reactions
  final String _htmlContent = '''
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=5.0, user-scalable=yes">
  <title>Native Emoji Reactions</title>
  <style>
    body {
      font-family: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      margin: 0;
      padding: 0;
      display: flex;
      flex-direction: column;
      height: 100vh;
      font-size: 16px;
    }

    .post {
      padding: 1rem;
      border-bottom: 1px solid #e0e0e0;
      background: white;
    }

    .reactions-container {
      display: flex;
      flex-wrap: wrap;
      gap: 0.5rem;
      margin-top: 0.75rem;
    }

    .reaction {
      display: flex;
      align-items: center;
      padding: 0.25rem 0.5rem;
      background-color: #f0f2f5;
      border-radius: 1rem;
      cursor: pointer;
      user-select: none;
      transition: background-color 0.2s;
    }

    .reaction:hover {
      background-color: #e4e6eb;
    }

    .reaction.active {
      background-color: #e7f3ff;
    }

    .reaction-emoji {
      font-size: 1.125rem;
      margin-right: 0.25rem;
    }

    .reaction-count {
      font-size: 0.875rem;
    }

    .emoji-picker {
      padding: 0.75rem;
      display: flex;
      flex-wrap: wrap;
      gap: 0.75rem;
      background-color: #f8f9fa;
      border-top: 1px solid #e0e0e0;
    }

    .emoji-btn {
      font-size: 1.5rem;
      cursor: pointer;
      user-select: none;
      transition: transform 0.1s;
    }

    .emoji-btn:hover {
      transform: scale(1.2);
    }
  </style>
</head>
<body>
  <div class="post">
    <div>
      <h3>Flutter Web with Native Emoji</h3>
      <p>This is a demo of using native emoji in Flutter Web via iframe.</p>
    </div>
    <div class="reactions-container" id="reactions">
      <!-- Reactions will be added here -->
    </div>
  </div>

  <div class="emoji-picker">
    <span class="emoji-btn" onclick="addReaction('👍')">👍</span>
    <span class="emoji-btn" onclick="addReaction('❤️')">❤️</span>
    <span class="emoji-btn" onclick="addReaction('😂')">😂</span>
    <span class="emoji-btn" onclick="addReaction('😮')">😮</span>
    <span class="emoji-btn" onclick="addReaction('😢')">😢</span>
    <span class="emoji-btn" onclick="addReaction('😡')">😡</span>
    <span class="emoji-btn" onclick="addReaction('🎉')">🎉</span>
    <span class="emoji-btn" onclick="addReaction('🚀')">🚀</span>
  </div>

  <script>
    // Store reaction counts
    let reactions = {};

    // Function to add or update a reaction
    function addReaction(emoji) {
      if (!reactions[emoji]) {
        reactions[emoji] = 0;
      }
      reactions[emoji]++;
      updateReactions();

      // Send data to Flutter via postMessage
      window.parent.postMessage({
        type: 'reaction_updated',
        emoji: emoji,
        count: reactions[emoji]
      }, '*');
    }

    // Function to update the reactions display
    function updateReactions() {
      const container = document.getElementById('reactions');
      container.innerHTML = '';

      Object.keys(reactions).forEach(emoji => {
        if (reactions[emoji] > 0) {
          const reaction = document.createElement('div');
          reaction.className = 'reaction';
          reaction.onclick = () => addReaction(emoji);

          const emojiSpan = document.createElement('span');
          emojiSpan.className = 'reaction-emoji';
          emojiSpan.textContent = emoji;

          const countSpan = document.createElement('span');
          countSpan.className = 'reaction-count';
          countSpan.textContent = reactions[emoji];

          reaction.appendChild(emojiSpan);
          reaction.appendChild(countSpan);
          container.appendChild(reaction);
        }
      });
    }

    // Function to set initial reaction data from Flutter
    function setReactions(reactionData) {
      try {
        reactions = JSON.parse(reactionData);
        updateReactions();
      } catch (e) {
        console.error('Error parsing reaction data:', e);
      }
    }

    // Listen for messages from Flutter
    window.addEventListener('message', function(event) {
      const data = event.data;

      if (data && data.type === 'add_reaction') {
        addReaction(data.emoji);
      } else if (data && data.type === 'set_reactions') {
        setReactions(data.reactions);
      }
    });

    // Notify Flutter when the page is fully loaded
    window.addEventListener('load', () => {
      window.parent.postMessage({
        type: 'webview_loaded'
      }, '*');
    });
  </script>
</body>
</html>
  ''';

  @override
  void initState() {
    super.initState();
    _setupIframe();
  }

  void _setupIframe() {
    // Register the iframe view factory
    ui.platformViewRegistry.registerViewFactory(
      _viewType,
      (int viewId) {
        // Create an iframe element
        _iframeElement = html.IFrameElement()
          ..style.border = 'none'
          ..style.height = '100%'
          ..style.width = '100%'
          ..srcdoc = _htmlContent;

        // Setup message communication
        html.window.addEventListener('message', _handleMessageEvent);

        return _iframeElement;
      },
    );

    // Create a message channel for more secure communication
    _channel = html.MessageChannel();
  }

  void _handleMessageEvent(html.Event event) {
    if (event is html.MessageEvent) {
      final data = event.data;

      if (data is Map) {
        if (data['type'] == 'reaction_updated') {
          setState(() {
            _reactionCounts[data['emoji']] = data['count'];
          });
        } else if (data['type'] == 'webview_loaded') {
          setState(() {
            _webViewLoaded = true;
          });

          // Send initial data if available
          if (_reactionCounts.isNotEmpty) {
            _sendReactionsToWebView();
          }
        }
      }
    }
  }

  void _sendReactionsToWebView() {
    final jsonData = jsonEncode(_reactionCounts);
    _iframeElement.contentWindow?.postMessage({
      'type': 'set_reactions',
      'reactions': jsonData
    }, '*');
  }

  void _addEmojiReaction(String emoji) {
    _iframeElement.contentWindow?.postMessage({
      'type': 'add_reaction',
      'emoji': emoji
    }, '*');
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Native Emoji Reactions'),
        backgroundColor: Theme.of(context).colorScheme.inversePrimary,
      ),
      body: Column(
        children: [
          // Instructions
          Padding(
            padding: const EdgeInsets.all(16.0),
            child: Card(
              child: Padding(
                padding: const EdgeInsets.all(16.0),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'Native Emoji in Flutter Web',
                      style: Theme.of(context).textTheme.headlineSmall,
                    ),
                    const SizedBox(height: 8),
                    const Text(
                      'This demo shows how to use native browser emojis in Flutter web via an iframe. '
                      'The emojis below come from your system and are rendered by the browser, not Flutter.',
                    ),
                    const SizedBox(height: 16),
                    Text(
                      'Current Reactions:',
                      style: Theme.of(context).textTheme.titleMedium,
                    ),
                    const SizedBox(height: 8),
                    Wrap(
                      spacing: 8,
                      children: _reactionCounts.entries.map((entry) {
                        return Chip(
                          label: Text('${entry.key} × ${entry.value}'),
                        );
                      }).toList(),
                    ),
                  ],
                ),
              ),
            ),
          ),

          // WebView for emoji reactions
          Expanded(
            child: HtmlElementView(viewType: _viewType),
          ),

          // Flutter-side emoji picker
          Container(
            padding: const EdgeInsets.all(16),
            decoration: BoxDecoration(
              color: Theme.of(context).colorScheme.surface,
              boxShadow: [
                BoxShadow(
                  color: Colors.black.withOpacity(0.1),
                  blurRadius: 4,
                  offset: const Offset(0, -2),
                ),
              ],
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  'Add reaction from Flutter:',
                  style: Theme.of(context).textTheme.titleMedium,
                ),
                const SizedBox(height: 8),
                Wrap(
                  spacing: 16,
                  children: [
                    _emojiButton('🔥', onTap: () => _addEmojiReaction('🔥')),
                    _emojiButton('👏', onTap: () => _addEmojiReaction('👏')),
                    _emojiButton('🤔', onTap: () => _addEmojiReaction('🤔')),
                    _emojiButton('👀', onTap: () => _addEmojiReaction('👀')),
                    _emojiButton('💯', onTap: () => _addEmojiReaction('💯')),
                    _emojiButton('🏆', onTap: () => _addEmojiReaction('🏆')),
                  ],
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _emojiButton(String emoji, {required Function() onTap}) {
    return InkWell(
      onTap: onTap,
      borderRadius: BorderRadius.circular(8),
      child: Container(
        padding: const EdgeInsets.all(8),
        child: Text(
          emoji,
          style: const TextStyle(fontSize: 24),
        ),
      ),
    );
  }

  @override
  void dispose() {
    // Remove event listener
    html.window.removeEventListener('message', _handleMessageEvent);
    super.dispose();
  }
}
